action.old_str:
void
EmitIR::operator()(VarDecl* obj)
{
  // 全局变量
  if (mCurFunc == nullptr) {
    auto ty = self(obj->type);
    llvm::Constant* initVal;
    if (obj->init)
      initVal = llvm::dyn_cast<llvm::Constant>(self(obj->init));
    else
      initVal = llvm::Constant::getNullValue(ty);
    auto gv = new llvm::GlobalVariable(
      mMod, ty, obj->type->qual.const_,
      llvm::GlobalVariable::ExternalLinkage, initVal, obj->name);
    obj->any = gv;
    return;
  }

  // 局部变量
  auto ty = self(obj->type);
  auto alloca = getOrCreateAlloca(ty, obj->name);
  obj->any = alloca;
  if (obj->init) {
    auto initVal = self(obj->init);
    mCurIrb->CreateStore(initVal, alloca);
  }
}

action.new_str:
void
EmitIR::operator()(VarDecl* obj)
{
  fprintf(stderr, "VarDecl: name=%s mCurFunc=%p\n", obj->name.c_str(), (void*)mCurFunc);
  // 全局变量
  if (mCurFunc == nullptr) {
    auto ty = self(obj->type);
    fprintf(stderr, "VarDecl: global, ty=%p\n", ty);
    llvm::Constant* initVal;
    if (obj->init) {
      fprintf(stderr, "VarDecl: has init\n");
      auto v = self(obj->init);
      fprintf(stderr, "VarDecl: init val=%p\n", v);
      initVal = llvm::dyn_cast<llvm::Constant>(v);
      fprintf(stderr, "VarDecl: initVal=%p\n", initVal);
    }
    else
      initVal = llvm::Constant::getNullValue(ty);
    fprintf(stderr, "VarDecl: creating global\n");
    auto gv = new llvm::GlobalVariable(
      mMod, ty, obj->type->qual.const_,
      llvm::GlobalVariable::ExternalLinkage, initVal, obj->name);
    obj->any = gv;
    fprintf(stderr, "VarDecl: global done\n");
    return;
  }

  // 局部变量
  auto ty = self(obj->type);
  auto alloca = getOrCreateAlloca(ty, obj->name);
  obj->any = alloca;
  if (obj->init) {
    auto initVal = self(obj->init);
    mCurIrb->CreateStore(initVal, alloca);
  }
}

